import{c as t,Q as s,j as n,m as i}from"./chunks/framework.CQedrDFh.js";const g=JSON.parse('{"title":"MongoDB 简介","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/mongo/index.md","filePath":"middleware/mongo/index.md","lastUpdated":1778503884000}'),e={name:"middleware/mongo/index.md"};function l(o,a,d,r,h,p){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="mongodb-jian-jie" tabindex="-1">MongoDB 简介 <a class="header-anchor" href="#mongodb-jian-jie" aria-label="Permalink to &quot;MongoDB 简介&quot;">​</a></h1><p>MongoDB 是一个开源、面向文档的 NoSQL 数据库，用 C++ 编写。与传统关系型数据库不同，MongoDB 使用类似 JSON 的 <strong>BSON</strong>（Binary JSON）格式存储数据，具有灵活的动态模式。</p><h2 id="yu-guan-xi-xing-shu-ju-ku-dui-bi" tabindex="-1">与关系型数据库对比 <a class="header-anchor" href="#yu-guan-xi-xing-shu-ju-ku-dui-bi" aria-label="Permalink to &quot;与关系型数据库对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比</th><th>关系型数据库</th><th>MongoDB</th></tr></thead><tbody><tr><td>数据模型</td><td>表（Table） → 行（Row）</td><td>集合（Collection） → 文档（Document）</td></tr><tr><td>Schema</td><td>预定义、严格</td><td>动态、灵活</td></tr><tr><td>扩展方式</td><td>垂直扩展为主</td><td>水平扩展（分片）</td></tr><tr><td>事务</td><td>强 ACID</td><td>v4.0+ 多文档 ACID</td></tr></tbody></table><h2 id="he-xin-te-xing" tabindex="-1">核心特性 <a class="header-anchor" href="#he-xin-te-xing" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><ul><li><strong>文档模型</strong>：数据以嵌套文档和数组的形式组织，贴近面向对象编程</li><li><strong>高可用</strong>：通过副本集（Replica Set）实现自动故障转移</li><li><strong>水平扩展</strong>：通过分片（Sharding）将数据分布到多台机器</li><li><strong>丰富的查询语言</strong>：支持增删改查、聚合管道、全文搜索、地理空间查询</li><li><strong>灵活的索引</strong>：支持单字段、复合、文本、地理空间等多种索引类型</li></ul><h2 id="ji-ben-gai-nian" tabindex="-1">基本概念 <a class="header-anchor" href="#ji-ben-gai-nian" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><h3 id="shu-ju-ku-ceng-ji" tabindex="-1">数据库层级 <a class="header-anchor" href="#shu-ju-ku-ceng-ji" aria-label="Permalink to &quot;数据库层级&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MongoDB 实例</span></span>
<span class="line"><span>└── 数据库（Database）</span></span>
<span class="line"><span>    └── 集合（Collection）</span></span>
<span class="line"><span>        └── 文档（Document）</span></span></code></pre></div><table tabindex="0"><thead><tr><th>层级</th><th>说明</th></tr></thead><tbody><tr><td><strong>Database</strong></td><td>一个实例可包含多个数据库，每个数据库有独立的权限和文件</td></tr><tr><td><strong>Collection</strong></td><td>类似 SQL 中的表，无需预定义 Schema，文档可具有不同字段</td></tr><tr><td><strong>Document</strong></td><td>BSON 格式的键值对，支持嵌套文档和数组</td></tr></tbody></table><h3 id="ji-ben-cao-zuo" tabindex="-1">基本操作 <a class="header-anchor" href="#ji-ben-cao-zuo" aria-label="Permalink to &quot;基本操作&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 连接</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mongosh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看所有数据库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dbs</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 切换 / 创建数据库（使用时自动创建）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">use</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mydb</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看当前数据库的集合</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> collections</span></span></code></pre></div><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://www.mongodb.com/docs/" target="_blank" rel="noreferrer">MongoDB Official Documentation</a></li></ul>`,14)])])}const u=t(e,[["render",l]]);export{g as __pageData,u as default};
